import * as React from 'react';
import { CallStatus } from '@/types/api.types';
import { IdentityDisplay } from './IdentityDisplay';
import { Alert, Box, Button, Card, CardContent, Stack, Typography } from '@mui/material';
import { toJpeg } from 'html-to-image';
import DownloadIcon from '@mui/icons-material/Download';
import BadgeIcon from '@mui/icons-material/Badge';
import PhotoCameraIcon from '@mui/icons-material/PhotoCamera';
import { PageContainer } from '@/components/PageContainer';
import { StatusMessage } from '@/components/StatusMessage';
import { useProfilesStore } from '@/store';
import { ApiGlobalStateManager } from '@/lib/api-state';
import { ProfileServices, ProfileServicesError } from '@/api';
import { Link } from '@tanstack/react-router';

export const IdentityView: React.FC = () => {
    const { profileState, setProfileState } = useProfilesStore();
    const hasFetchedRef = React.useRef<boolean>(false);

    const handleDownload = async () => {
        try {
            const node = document.getElementById('alumniId')?.children[0] as HTMLElement;
            if (!node) return;

            // Convert the avatar image to a data URL to avoid cross-origin canvas tainting
            const imgEl = node.querySelector('img') as HTMLImageElement | null;
            let originalSrc = '';
            if (imgEl?.src) {
                originalSrc = imgEl.src;
                try {
                    const resp = await fetch(imgEl.src);
                    const blob = await resp.blob();
                    const dataUrl = await new Promise<string>((resolve) => {
                        const reader = new FileReader();
                        reader.onloadend = () => resolve(reader.result as string);
                        reader.readAsDataURL(blob);
                    });
                    imgEl.src = dataUrl;
                } catch {
                    // continue with original src
                }
            }

            const dataUrl = await toJpeg(node, { quality: 0.95, skipFonts: true });

            // Restore original src
            if (imgEl && originalSrc) {
                imgEl.src = originalSrc;
            }

            const link = document.createElement('a') as HTMLAnchorElement;
            link.download = `Alumni_Id_${profileState.data.id}.jpeg`;
            link.href = dataUrl;
            link.click();
        }
        catch {
            // swallow download errors silently
        }
    };

    React.useEffect(() => {
        if (!profileState.data.id && !hasFetchedRef.current) {
            hasFetchedRef.current = true;
            ApiGlobalStateManager(ProfileServices.GetProfile(), setProfileState);
        }
    }, []);

    const headerProps = {
        icon: <BadgeIcon color="primary" />,
        title: 'Digital identity card',
        subtitle: 'Your alumni ID, signed by the network. Show it for in-person verification or download it as an image.',
    };

    if (profileState.status !== CallStatus.Success) {
        return (
            <PageContainer {...headerProps}>
                <Card>
                    <CardContent>
                        <StatusMessage
                            notStartedMessage="Loading your digital identity card..."
                            failureMessage={ProfileServicesError.GetProfileError(profileState.httpStatus)}
                            currentStatus={profileState.status}
                            correlationId={profileState.correlationId}
                        />
                    </CardContent>
                </Card>
            </PageContainer>
        );
    }

    const hasPhoto = !!profileState.data.photo;

    return (
        <PageContainer {...headerProps}>
            {!hasPhoto && (
                <Alert severity="info" icon={<PhotoCameraIcon />} sx={{ mb: 2 }}>
                    <Typography variant="body2" sx={{ fontWeight: 600, mb: 0.5 }}>
                        Add a profile photo to unlock your ID card
                    </Typography>
                    <Typography variant="caption" component="div">
                        Your alumni ID needs a photo to be valid for verification.{' '}
                        <Link to="/profile/photo">Upload your photo</Link> to continue.
                    </Typography>
                </Alert>
            )}

            <Card>
                <CardContent>
                    <Stack spacing={2} sx={{ alignItems: 'center' }}>
                        <Box id="alumniId">
                            <IdentityDisplay {...profileState.data} />
                        </Box>
                        {hasPhoto && (
                            <Button
                                variant="contained"
                                color="primary"
                                onClick={handleDownload}
                                startIcon={<DownloadIcon />}
                                sx={{ textTransform: 'none' }}
                            >
                                Download as image
                            </Button>
                        )}
                    </Stack>
                </CardContent>
            </Card>
        </PageContainer>
    );
};
